        int n = nums.size();
        vector<int> res(n, -1);
        stack<int> st;
        for (int i = 0; i < n; i++) {
            // Compare elements visually
            while (!st.empty() && compare(st.top(), i)) {
                int poppedIdx = st.top();
                st.pop();
                res[poppedIdx] = nums[i];
                resolve(poppedIdx, nums[i]);
            }
            st.push(i);
        }
        return res;
    }
};

