class Solution {
public:
    void dfs(vector<vector<int>>& grid, int r, int c) {
        int rows = grid.size();
        int cols = grid[0].size();
        if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] != 1) {
            return;
        }

        // Focus & Update grid cell visually using our SDK
        focus_cell(r, c);
        grid[r][c] = 8; // Change visited value
        update_cell(r, c, 8);

        dfs(grid, r + 1, c);
        dfs(grid, r - 1, c);
        dfs(grid, r, c + 1);
        dfs(grid, r, c - 1);
    }

    void islandTraversal(vector<vector<int>>& grid) {
        if (grid.empty()) return;
        dfs(grid, 0, 0);
    }
};

