class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        ListNode* prev = nullptr;
        ListNode* curr = head;

        while (curr != nullptr) {
            ListNode* temp = curr->next;

            // Visual pointers update using our custom Linked List SDK!
            focus_node(curr, "curr");
            if (prev) focus_node(prev, "prev");
            if (temp) focus_node(temp, "temp");

            // Perform link reassignment in C++
            curr->next = prev;

            // Log pointer update step
            update_next(curr, prev);

            // Move pointer references
            prev = curr;
            curr = temp;
        }
        return prev;
    }
};

