public:
    bool isValid(vector<int>& nums) {
        stack<int> st;
        auto open = [](int t) { return t == 1 || t == 3 || t == 5; };
        auto matches = [](int openT, int closeT) {
            return (openT == 1 && closeT == 2) || (openT == 3 && closeT == 4) || (openT == 5 && closeT == 6);
        };
        for (int i = 0; i < (int)nums.size(); i++) {
            int c = nums[i];
            if (open(c)) {
                st.push(c);
            } else {
                if (st.empty()) return false;
                int top = st.top();
                st.pop();
                if (!matches(top, c)) return false;
            }
        }
        return st.empty();
    }
};

